INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-d0d1b9a2-moex-00063', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '柏嚴公司於X3年初成立，5月10日以現金購入甲、乙兩筆股票，並分類為透過其他綜合損 益按公允價值衡量之權益工具投資，其相關資料如下： 成本 X3年底公允價值 X4年底公允價值 甲股票 $2,500,000 $2,900,000 $3,200,000 乙股票 4,600,000 4,500,000 柏嚴公司於 X4年10月20日以$4,300,000出售乙股票。試計算X4年之綜合損益表中列報 之其他綜合損益金額為：', '["$100,000", "$400,000", "$(200,000)", "$300,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00064', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '高富公司於X6年1月1日購買一台營業用設備，成本$4,800,000（內含可個別辨認之重大安 檢成本$300,000），後續採成本模式衡量。設備之估計耐用年限為 15 年，直線法提列折舊， 估計殘值為零。基於安全法規要求，購入後每5年須進行一次重大安檢。X8年底，為保障使 用者安全，法規修改為安檢須每 3 年進行一次，X8 年 12 月 31 日實際支付之安檢成本為 $480,000。試計算X9年該設備相關之折舊費用金額為：', '["$320,000", "$360,000", "$420,000", "$460,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00065', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '君繁公司X4年1月1日開始自建廠房，預計X6年年底完工。X4年1月1日取得3年期專 案借款$800,000，利率 12%，每年年底付息。同期間尚有兩筆全年流通在外之一般性借款， 其中一筆面額為$5,000,000，利率10%，每年年底付息；另一筆面額為$4,000,000，利率8%， 每年年底付息。X4年之工程支出為$1,400,000，發生在年初。X4年最後5個月，因為未做好 防颱措施，工地遭7月底的颱風嚴重破壞而停工。試計算X4年資本化之借款成本金額：', '["$56,000", "$78,333", "$87,889", "$150,666"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00066', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', 'X6年度東文公司銷售機器設備，並附帶3年的保證型保固服務。根據歷史經驗，履行保固責 任的成本估計在銷售後第一年、第二年與第三年分別為銷貨收入的2%、4%與5%。X6年到 X8年之銷貨與實際售後服務保證費用如下： 年度 成本 實際售後服務保證費用 X6 $1,100,000 $20,600 X7 1,500,000 51,300 X8 2,300,000 126,500 $4,900,000 $198,400 試問X8年12月31日東文公司應報導的產品保固負債準備金額為：', '["$0", "$161,000", "$198,400", "$340,600"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00067', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '飛翔公司於X5年1月1日以$2,165,754發行8年期之可買回公司債，面額$2,000,000、票面 利率6%，每年底支付利息，另發生交易成本$12,000。飛翔公司得自X8年1月1日起，以 $2,000,000 加應計利息之金額買回公司債。發行時經評價之結果，嵌入式之買回權資產的公 允價值為$86,265。公司認為買回權與公司債兩者經濟特性及風險並未緊密關聯，因此，將嵌 入式買回權自上述混合工具（hybridinstrument）分離，公司債作為主契約採用攤銷後成本進 行會計處理。試計算飛翔公司發行此一混合工具之主契約之公司債，應認列之金額為：', '["$2,153,754", "$2,154,214", "$2,240,462", "$2,252,019"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00068', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '東寧公司 X2 年初將一項機器設備（成本為$1,500,000，累計折舊$300,000）按照公允價值 $1,300,000出售至中華公司並立即租回（此交易滿足IFRS15資產銷售之規定），租期5年， 每年年底支付租金$180,000，中華公司之租賃隱含利率為8%，租期屆滿時東寧公司須將該機 器設備退還中華公司，設備在租期屆滿日之保證估計殘值$250,000，東寧公司預估租期屆滿 時須就保證殘值支付中華公司$20,000。試計算X2年東寧公司認列之售後租回移轉權利損益 金額為：（註：複利現值因子，4期，8%=0.735030，5期，8%=0.680583；普通年金現值因子， 4期，8%=3.312127，5期8%=3.992710）', '["售後租回移轉權利利益$31,628", "售後租回移轉權利利益$43,669", "售後租回移轉權利利益$100,000", "無需認列售後租回移轉權利損益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00069', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '南投公司以間接法編製現金流量表。下列有幾項應在其營業活動現金流量中列為本期損益之 加項？', '["處分機器設備之利益", "透過其他綜合損益按公允價值衡量之證券投資，於期末評價產生之未實現損失增加數", "權益證券投資採權益法處理所認列之投資損失", "融資租賃中使用權資產之折舊費用。 ⑤依員工認股計畫所認列之酬勞費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00070', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '彰化公司X1年度的普通股全年流通在外股數為2,000,000股，每股面值$10，全年平均市價 為$20，本期淨利為$4,500,000。該公司另有 3%不可轉換的累積特別股（已積欠 2 年股利） 1,000,000股，每股面值$10，全年流通在外。彰化公司曾於之前年度給予員工認股權600,000 股，可按每股$15的價格認購普通股，X1年未有人行使。試問彰化公司X1年度的稀釋每股 盈餘為何？', '["$1.67", "$1.80", "$1.95", "$2.10"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00071', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '楠梓公司X7年與退休金相關的資訊如下：X7年初的確定給付義務現值為$520,000，計畫資 產公允價值為$280,000。X7 年度當期服務成本$213,500，年底提撥$350,000，支付退休金 $145,000，折現率8%，計畫資產實際報酬$13,000。因精算假設改變，重新計算X7年底的確 定給付義務現值為$750,000。試問下列敘述何者正確？', '["X7年度計畫資產利益$9,400", "X7年度精算損失$119,900", "X7年度退休金費用$242,100", "X7年底應計退休金負債餘額$12,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00072', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '下列有關應收款項之敘述，何者錯誤？', '["企業出售附有買回選擇權的應收款項時，若買回價格為行使買回權時該應收款項之公允價 值，則企業不應除列該應收款項", "國際財務報導準則（IFRS）第15號「客戶合約之收入」中，企業產生收取款項之權利，若 款項之收取僅取決於時間經過，該權利應列報為應收帳款", "應收款項在原始認列後，若信用風險已顯著增加但尚未發生信用減損，應按存續期間預期 信用損失衡量該資產之備抵損失", "在預期信用損失模式之下，若應收款項尚未發生減損，利息收入仍依總帳面金額為計算基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL)
